CustomFunction.Calculation:
// Appends AND NOT EXISTS (SELECT ...) using a fully-assembled fmorm subquery object.
// The subquery's SQL is embedded directly; its bindings are appended.
// NOTE: NOT EXISTS subqueries require FileMaker 17+.
// Use QueryWhereExists_cf for EXISTS.
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_subSql = QueryToSQL_cf ( subquery ) ;
_subBindings = JSONGetElement ( subquery ; "bindings" ) ;
_subBindingCount = JSONGetElement ( subquery ; "bindingCount" ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "notExists" ; JSONString ] ;
	[ "sql" ; _subSql ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = If ( _subBindingCount > 0 ;
	QueryMergeBindings_cf ( _q2 ; _subBindings ; _subBindingCount ; 0 ) ;
	_q2
	)
];
_q3
)
